class Solution {
public:
    string reverseWords(string s) {
        string res;
        int n = s.size();
        int start = 0;
        for (int i = 0; i <= n; i++) {
            if (i == n || s[i] == ' ') {
                if (i != start) {
                    string temp = s.substr(start, i - start);
                    reverse(temp.begin(), temp.end());
                    res += temp + " ";
                }
                start = i + 1;
            }
        }
        return res.substr(0, res.size() - 1);
    }
};
```

